Steps:
[GQL-OP list_pages]
  query { pages(storeId: "{{STORE_ID}}" keyword: "" first: 10 cultureName: "en-US") { totalCount items { id name relativeUrl permalink } } }
[GQL-EXEC list_pages]

[GQL-OP page_bogus]
  query { page(storeId: "{{STORE_ID}}" id: "00000000-0000-0000-0000-000000000000" cultureName: "en-US") { id name } }
[GQL-EXEC page_bogus]

[GQL-OP de_pages]
  query { pages(storeId: "{{STORE_ID}}" keyword: "" first: 5 cultureName: "de-DE") { totalCount items { id name } } }
[GQL-EXEC de_pages]

[GQL-OP no_match]
  query { pages(storeId: "{{STORE_ID}}" keyword: "agent-test-xcms-no-match-zzz-2026" first: 10) { totalCount items { id } } }
[GQL-EXEC no_match]

[GQL-OP list_menus]
  query { menus(storeId: "{{STORE_ID}}" cultureName: "en-US") { name outerId items { title url priority } } }
[GQL-EXEC list_menus]

Assertions:
[ERRORS label=one_menu] errors[] empty
[DATA label=one_menu] data.menu is non-null
[DATA label=one_menu] data.menu.name = {{MENU_NAME}}

Steps:
[GQL-OP menu_bogus]
  query { menu(storeId: "{{STORE_ID}}" cultureName: "en-US" name: "agent-test-menu-nonexistent-2026") { name outerId } }
[GQL-EXEC menu_bogus]

[GQL-OP ctx_home]
  query { pageContext(storeId: "{{STORE_ID}}" domain: "{{STOREFRONT_DOMAIN}}" userId: "{{TEST_USER_ID}}" permalink: "/" cultureName: "en-US") { store { storeId storeName } slugInfo { redirectUrl entityInfo { objectType id } } user { id userName email memberId } whiteLabelingSettings { footerLinks { title } } } }
[GQL-EXEC ctx_home]

[GQL-OP list_docs]
  query { pageDocuments(storeId: "{{STORE_ID}}" keyword: "" first: 10 cultureName: "en-US") { totalCount items { id title permalink } } }
[GQL-EXEC list_docs]

[GQL-OP doc_bogus]
  query { pageDocument(id: "00000000-0000-0000-0000-000000000000") { id title permalink } }
[GQL-EXEC doc_bogus]

[GQL-OP ctx_catalog]
  query { pageContext(storeId: "{{STORE_ID}}" domain: "{{STOREFRONT_DOMAIN}}" userId: "{{TEST_USER_ID}}" permalink: "/catalog" cultureName: "en-US") { store { storeId storeName } slugInfo { redirectUrl entityInfo { objectType id semanticUrl } } user { id userName memberId } whiteLabelingSettings { footerLinks { title } } } }
[GQL-EXEC ctx_catalog]
